{"cmd":"# The server socket needs a client to connect first. Let me use expect instead.
kill 137 2>/dev/null; sleep 1

# Create an expect script that will automate everything
cat <<'EXPECTEOF' > /app/setup_alpine.exp
#!/usr/bin/expect -f
set timeout 60

# Start QEMU with serial socket
spawn qemu-system-x86_64 \
    -m 1024 \
    -hda /dev/null \
    -cdrom /app/alpine.iso \
    -boot d \
    -netdev user,id=net0,hostfwd=tcp::2222-:22 \
    -device virtio-net-pci,netdev=net0 \
    -serial unix:/tmp/alpine_serial,server,nowait \
    -monitor none 2>/dev/null

# Wait for boot prompt
sleep 15

# Connect to the serial socket using socat in background
exec socat /tmp/alpine_serial stdio &
set socat_pid $spawn_out_pid

# Now interact with the Alpine installer
expect {
    "boot:" {
        puts "Got boot prompt"
    }
    timeout {
        puts "Timeout - trying anyway"
    }
}

# Try to boot and get a shell
send "alpine\r"
sleep 5

expect {
    "~ # " {
        puts "Got root shell!"
    }
    "login: " {
        send "root\r"
        sleep 2
    }
    timeout {
        puts "Timeout waiting for shell"
    }
}

# Now configure the system
# Set password
send "echo 'root:password123' | chpasswd\r"
sleep 3

expect {
    "~ # " {
        puts "Password set"
    }
    timeout {
        puts "Timeout setting password"
    }
}

# Install and start openssh
send "apk add openssh\r"
sleep 10

expect {
    "~ # " {
        puts "OpenSSH installed"
    }
    timeout {
        puts "Timeout installing OpenSSH"
    }
}

# Start sshd
send "/usr/sbin/sshd\r"
sleep 3

expect {
    "~ # " {
        puts "sshd started"
    }
    timeout {
        puts "Timeout starting sshd"
    }
}

# Keep the session alive
interact
EXPECTEOF
chmod +x /app/setup_alpine.exp"}

